mapper.select:
SELECT COUNT(*)
FROM J_직원_사이트접속
WHERE 직원아이디 = #{userId}
  AND 사이트코드 = #{siteCode}
  AND ISNULL(부서코드, N'') = ISNULL(NULLIF(#{deptCode,jdbcType=NVARCHAR}, N''), N'')

mapper.update:
UPDATE J_직원_사이트접속
SET 접속허용 = #{accessAllowed},
    사이트내권한 = #{siteRole,jdbcType=NVARCHAR}
WHERE 접속PK = #{accessPk}
